let done = 0;
for (const file of files) {
  if (!file.isNew && !existsSync(file.path)) {
    console.error(
      `ERROR: ${file.path} no existe -- ejecuta esto desde la raiz correcta del repo, tras los scripts anteriores.`,
    );
    process.exit(1);
  }
  mkdirSync(dirname(file.path), { recursive: true });
  writeFileSync(file.path, file.content, 'utf8');
  const written = readFileSync(file.path, 'utf8');
  if (written !== file.content) {
    console.error(`ERROR: verificacion fallida en ${file.path}`);
    process.exit(1);
  }
  console.log(`OK  ${file.isNew ? '(nuevo) ' : ''}${file.path}`);
  done += 1;
}

console.log(`\n${done}/${files.length} archivos aplicados y verificados.`);
